// mamba_scan.cu — custom GPU kernel for the Mamba-1 (S6) selective-scan step.
//
// WHY (proven by measurement): falcon-mamba-7b decodes at ~0.45 tok/s. The Q8
// matmuls (in_proj/out_proj/lm_head) are already GPU-fast (~0.3-0.5 ms via
// q8_gemv.cu); the bottleneck is the CPU S6 recurrence in `mamba1_s6_step`
// (~2.2 s/token). The recurrence per layer is d_inner × d_state (8192 × 16 =
// 131072) fused multiply-adds, EACH with two fp32 exp() calls → ~8.4 M exp/token
// across 64 layers. That double-exp inner loop is the whole cost.
//
// This kernel moves exactly that loop to the GPU with IDENTICAL numerics. The
// per-channel recurrent state `h` [d_inner × d_state] stays RESIDENT in VRAM
// across tokens (seeded once from the host CPU state on first use, updated
// in-place every step, reset via `mamba_scan_reset_all`) — no per-token H2D/D2H
// of the state. Only the small per-token vectors (dt, B, C, x_conv, y ≈ 64 KB)
// cross the bus; the dominant a_log matrix and d_skip vector are uploaded ONCE
// and kept resident.
//
// Recurrence (per layer), matching mamba1_s6_step EXACTLY:
//   A     = -exp(a_log[ch,s])                     (continuous diagonal A)
//   Abar  = exp(dt[ch] * A) = exp(-dt[ch] * exp(a_log[ch,s]))  in (0,1)
//   h[ch,s] = h[ch,s] * Abar + dt[ch] * B[s] * x[ch]
//   y[ch]   = D[ch] * x[ch] + Σ_s C[s] * h[ch,s]
// FalconMamba's weightless RMSNorm on dt/B/C is applied on the HOST before this
// kernel (it is cheap and shape-preserving), so B/C/dt arrive already-normed and
// the kernel is arch-agnostic — vanilla Mamba-1 and FalconMamba hit the SAME
// kernel, differing only in whether the host normed the inputs.
//
// NUMERICS: fp32 throughout, PRECISE `expf` (NOT the fast `__expf` intrinsic) so
// the nested exp matches the CPU `f32::exp` (libm) reference within the qspec's
// 1e-4 max_rel_err gate. Multiplication/accumulation order is byte-identical to
// the CPU loop (left-associative, state order s=0..d_state).
//
// THREAD MAPPING: ONE THREAD PER CHANNEL `ch` (d_inner threads). Each thread
// owns its row of `h` [d_state contiguous] and sweeps s=0..d_state, accumulating
// y[ch] locally (no cross-thread reduction — the sum over s lives in one thread).
// B and C (length d_state, shared by ALL channels) are staged in shared memory
// once per block. d_state is tiny (16), so the per-thread loop is short and the
// kernel is latency/occupancy-light but ~1000× the CPU scan — ample for the
// 5-10 tok/s gate.
//
// Build: compiled to a native CUBIN at build time by build.rs via
// `nvcc --cubin -arch=<MESH_CUDA_ARCH default sm_89>`; loaded at runtime through
// the cudarc DRIVER (cuModuleLoadData) — no runtime NVRTC. Gated by MESH_GPU_SCAN=1.

extern "C" __global__ void mamba1_s6_scan(
    const float* __restrict__ x_conv, // [d_inner] conv output (the "x")
    const float* __restrict__ dt,     // [d_inner] softplus(dt_proj·dt_src + bias)
    const float* __restrict__ b_vec,  // [d_state] B (already RMSNormed for falcon)
    const float* __restrict__ c_vec,  // [d_state] C (already RMSNormed for falcon)
    const float* __restrict__ a_log,  // [d_inner * d_state] log-A, row-major [ch,s]
    const float* __restrict__ d_skip, // [d_inner] D skip connection
    float* __restrict__ h,            // [d_inner * d_state] recurrent state (in/out)
    float* __restrict__ y,            // [d_inner] output
    int d_inner,
    int d_state)
{
    // Stage B and C in shared memory: every channel reads the SAME length-d_state
    // B and C, so one cooperative load per block kills d_inner-fold redundant
    // global traffic. Layout: [0..d_state) = B, [d_state..2*d_state) = C.
    extern __shared__ float bc[];
    for (int i = threadIdx.x; i < d_state; i += blockDim.x) {
        bc[i]           = b_vec[i];
        bc[d_state + i] = c_vec[i];
    }
    __syncthreads();

    const int ch = blockIdx.x * blockDim.x + threadIdx.x;
    if (ch >= d_inner) return;

    const float* __restrict__ bs = bc;
    const float* __restrict__ cs = bc + d_state;

    const float dt_ch = dt[ch];
    const float x_ch  = x_conv[ch];
    // yi = D[ch] * x[ch]  (the D-skip term, added BEFORE the state sum — exactly
    // the CPU init `let mut yi = d_skip[ch] * x_conv[ch];`).
    float yi = d_skip[ch] * x_ch;

    const int base = ch * d_state;
    #pragma unroll 4
    for (int s = 0; s < d_state; ++s) {
        const int idx = base + s;
        // Abar = exp(-dt * exp(a_log)). PRECISE expf (matches CPU f32::exp).
        const float a  = expf(-dt_ch * expf(a_log[idx]));
        // h = h*Abar + (dt*B)*x  — left-assoc, identical to the CPU kernel.
        const float hv = h[idx] * a + dt_ch * bs[s] * x_ch;
        h[idx] = hv;
        yi += cs[s] * hv;
    }
    y[ch] = yi;
}
